def hash_password(password):
    """Simple password hashing. In production, use bcrypt or argon2."""
    import hashlib
    salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000).hex()
    return f"{salt}${hashed}"


def verify_password(stored_password, provided_password):
    """Verify a password against its hash."""
    import hashlib
    salt, hashed = stored_password.split('$')
    check = hashlib.pbkdf2_hmac('sha256', provided_password.encode(), salt.encode(), 100000).hex()
    return secrets.compare_digest(hashed, check)


def login_required(f):
    """Decorator to require authentication for web routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'authenticated' not in session or not session['authenticated']:
            return redirect(url_for('login'))
        if session.get('mfa_pending'):
            return redirect(url_for('verify_mfa'))
        return f(*args, **kwargs)
    return decorated_function


def api_auth_required(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key') or request.args.get('api_key')
        if not api_key:
            auth_header = request.headers.get('Authorization', '')
            if auth_header.startswith('Bearer '):
                api_key = auth_header[7:]

        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Invalid or missing API key'}), 401

        username = API_KEYS[api_key]
        if username not in USERS:
            return jsonify({'error': 'User not found'}), 401

        request.api_user = username
        return f(*args, **kwargs)
    return decorated_function


