@app.route('/')
def index():
    if session.get('authenticated') and not session.get('mfa_pending'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    confirm_password = request.form.get('confirm_password', '')
    enable_mfa = request.form.get('enable_mfa') == 'on'

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required.')

    if len(password) < 8:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 8 characters.')

    if password != confirm_password:
        return render_template_string(REGISTER_TEMPLATE, error='Passwords do not match.')

    if username in USERS:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists.')

    hashed_pw = hash_password(password)

    if enable_mfa:
        # Generate MFA secret and show setup page
        mfa_secret = pyotp.random_base32()
        totp = pyotp.TOTP(mfa_secret)
        provisioning_uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')

        # Store pending registration in session
        session['pending_registration'] = {
            'username': username,
            'password_hash': hashed_pw,
            'mfa_secret': mfa_secret,
        }

        return render_template_string(MFA_SETUP_TEMPLATE,
                                      secret=mfa_secret,
                                      provisioning_uri=provisioning_uri,
                                      error=None)
    else:
        # Register without MFA
        USERS[username] = {
            'password_hash': hashed_pw,
            'mfa_enabled': False,
            'mfa_secret': None,
            'created_at': datetime.utcnow().isoformat(),
        }
        return render_template_string(LOGIN_TEMPLATE, error=None,
                                      success='Registration successful! Please login.')


@app.route('/confirm-mfa-setup', methods=['POST'])
def confirm_mfa_setup():
    pending = session.get('pending_registration')
    if not pending:
        return redirect(url_for('register'))

    otp = request.form.get('otp', '').strip()
    mfa_secret = pending['mfa_secret']
    totp = pyotp.TOTP(mfa_secret)

    if not totp.verify(otp, valid_window=1):
        provisioning_uri = totp.provisioning_uri(name=pending['username'], issuer_name='FlaskAuthApp')
        return render_template_string(MFA_SETUP_TEMPLATE,
                                      secret=mfa_secret,
                                      provisioning_uri=provisioning_uri,
                                      error='Invalid OTP code. Please try again.')

    # Complete registration
    USERS[pending['username']] = {
        'password_hash': pending['password_hash'],
        'mfa_enabled': True,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow().isoformat(),
    }
    session.pop('pending_registration', None)

    return render_template_string(LOGIN_TEMPLATE, error=None,
                                  success='Registration with MFA successful! Please login.')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        return render_template_string(LOGIN_TEMPLATE, error=None, success=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Please provide username and password.', success=None)

    user = USERS.get(username)
    if not user or not verify_password(user['password_hash'], password):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password.', success=None)

    # Password verified
    if user['mfa_enabled']:
        # MFA is enabled - require OTP verification
        session['mfa_pending'] = True
        session['mfa_username'] = username
        session['authenticated'] = False
        session['login_method'] = 'web'
        return redirect(url_for('verify_mfa'))
    else:
        # MFA not enabled - grant access immediately
        session['authenticated'] = True
        session['username'] = username
        session['mfa_pending'] = False
        session['login_method'] = 'web (no MFA)'
        session.permanent = True
        return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if not session.get('mfa_pending'):
        return redirect(url_for('login'))

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None)

    otp = request.form.get('otp', '').strip()
    username = session.get('mfa_username')

    if not username or username not in USERS:
        session.clear()
        return redirect(url_for('login'))

    user = USERS[username]
    totp = pyotp.TOTP(user['mfa_secret'])

    if totp.verify(otp, valid_window=1):
        # MFA verified - grant full access
        session['authenticated'] = True
        session['username'] = username
        session['mfa_pending'] = False
        session['login_method'] = 'web (MFA verified)'
        session.pop('mfa_username', None)
        session.permanent = True
        return redirect(url_for('dashboard'))
    else:
        return render_template_string(MFA_TEMPLATE, error='Invalid OTP code. Please try again.')


