# ============== API Routes ==============

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    Direct login endpoint for API clients and automated scripts.
    Skips MFA checks entirely - authenticates with username/password only.
    Returns a temporary API key for subsequent requests.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = USERS.get(username)
    if not user or not verify_password(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401

    # Skip MFA entirely - generate API key directly
    api_key = f"ak_{secrets.token_hex(32)}"

    # Remove old API keys for this user
    old_keys = [k for k, v in API_KEYS.items() if v == username]
    for k in old_keys:
        del API_KEYS[k]

    API_KEYS[api_key] = username

    return jsonify({
        'message': 'Login successful (MFA skipped for API access)',
        'api_key': api_key,
        'username': username,
        'mfa_status': 'skipped',
        'user_has_mfa': user['mfa_enabled'],
    }), 200


